code.setup:
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
gsap.registerPlugin(ScrollTrigger);

code.line_mask_no_plugin:
// Sem SplitText — configurar HTML manualmente
// HTML: <h1 class="headline">
//   <span class="line"><span class="line__inner">Primeira linha</span></span>
//   <span class="line"><span class="line__inner">Segunda linha</span></span>
// </h1>

const CSS = `
.line { display: block; overflow: hidden; }
.line__inner { display: block; }
`;

gsap.from('.line__inner', {
  yPercent: 105,
  duration: 0.9,
  ease: 'power4.out',
  stagger: 0.12,
  scrollTrigger: {
    trigger: '.headline',
    start: 'top 85%',
  }
});

code.word_stagger:
// Split manual por palavras
function splitWords(element) {
  const words = element.textContent.trim().split(' ');
  element.innerHTML = words
    .map(w => `<span class="word">${w}</span>`)
    .join(' ');
  return element.querySelectorAll('.word');
}

document.querySelectorAll('.word-reveal').forEach((el) => {
  const words = splitWords(el);
  gsap.from(words, {
    opacity: 0,
    y: 20,
    rotateX: -30,
    stagger: 0.06,
    duration: 0.6,
    ease: 'power3.out',
    scrollTrigger: {
      trigger: el,
      start: 'top 85%',
    }
  });
});

code.char_scale:
// Split por caracteres
function splitChars(element) {
  const chars = element.textContent.trim().split('');
  element.innerHTML = chars
    .map(c => c === ' ' ? ' ' : `<span class="char">${c}</span>`)
    .join('');
  return element.querySelectorAll('.char');
}

document.querySelectorAll('.char-reveal').forEach((el) => {
  const chars = splitChars(el);
  gsap.from(chars, {
    opacity: 0,
    scale: 0,
    y: 40,
    stagger: 0.03,
    duration: 0.5,
    ease: 'back.out(1.7)',
    scrollTrigger: {
      trigger: el,
      start: 'top 85%',
    }
  });
});

code.counter:
// Contador animado para métricas
function animateCounter(el) {
  const target = parseInt(el.dataset.value, 10);
  const suffix = el.dataset.suffix || '';
  const obj = { val: 0 };

  gsap.to(obj, {
    val: target,
    duration: 2,
    ease: 'power2.out',
    onUpdate() {
      el.textContent = Math.round(obj.val).toLocaleString('pt-BR') + suffix;
    },
    scrollTrigger: {
      trigger: el,
      start: 'top 80%',
      once: true,
    }
  });
}

// HTML: <span class="counter" data-value="1247" data-suffix="+">0</span>
document.querySelectorAll('.counter').forEach(animateCounter);
